# fmt: on

# ─────────────────────────────────────────────────────────────────────────────
# 2. Parse into numpy arrays — exact logged values, zero noise
# ─────────────────────────────────────────────────────────────────────────────

encoder_row = np.array(ENCODER_ROW_RAW, dtype=np.float32)   # (168, 8)
decoder_row = np.array(DECODER_ROW_RAW, dtype=np.float32)   # (168, 11)
assert encoder_row.shape == (168, 8),  f"Expected (168,  8), got {encoder_row.shape}"
assert decoder_row.shape == (168, 11), f"Expected (168, 11), got {decoder_row.shape}"

# Feature names — must match DatasetCreation.py exactly
ENCODER_FEATURES = ['abvaerk', 'toutdoor', 'hour_sin', 'hour_cos',
                    'weekday_sin', 'weekday_cos', 'month_sin', 'month_cos']
DECODER_FEATURES = ['hour_sin', 'hour_cos', 'weekday_sin', 'weekday_cos',
                    'month_sin', 'month_cos',
                    'temperature', 'relativeHumidity', 'windSpeed',
                    'precipitation', 'cloudCover']

# ─────────────────────────────────────────────────────────────────────────────
# 3. Load norm stats + real target from dataset.pt, run real model inference
# ─────────────────────────────────────────────────────────────────────────────
from LSTMModel import Config, LSTMForecast

DATASET_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                            "..", "Files", "dataset.pt")
MODEL_PATH   = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                            "..", "Models", "model_v13", "model_v13.pth")

dataset     = torch.load(DATASET_PATH, weights_only=False)
demand_mean = float(dataset["demand_mean"])
demand_std  = float(dataset["demand_std"])

# Real target for sample 0 — normalised future abvaerk, rescaled to raw MWh
target_row = dataset["target"][0].numpy()                           # (168,)
targets_h  = (target_row * demand_std + demand_mean)[np.newaxis, :] # (1, 168)

# Build input tensors from the logged raw rows — shape (1, 168, features)
enc_tensor = torch.tensor(encoder_row[np.newaxis, :, :])  # (1, 168, 8)
dec_tensor = torch.tensor(decoder_row[np.newaxis, :, :])  # (1, 168, 11)

# Load model and run inference
checkpoint = torch.load(MODEL_PATH, map_location="cpu", weights_only=False)
config     = Config()
model      = LSTMForecast(config)
model.load_state_dict(checkpoint["model_state_dict"])
model.eval()

with torch.no_grad():
    mu, _ = model(enc_tensor, dec_tensor)   # mu shape: (1, 168)

preds_h = mu.numpy() * demand_std + demand_mean  # rescale to raw MWh

# test_start_global_idx = 0 → sample 0 of the whole dataset
test_start_global_idx = 0

# ─────────────────────────────────────────────────────────────────────────────
# 4. Call the plot function and save
# ─────────────────────────────────────────────────────────────────────────────
OUT_DIR = os.path.dirname(os.path.abspath(__file__))

save_path = os.path.join(OUT_DIR, "forecast_window_row0.png")
plot_forecast_windows(preds_h, targets_h, test_start_global_idx, save_path)
print(f"Saved: {save_path}")

